// Exemplo conceitual (Zod)
import { z } from "zod";

const Heading = z.object({
  type: z.literal("heading"),
  level: z.number().int().min(1).max(6),
  text: z.string().min(1),
});

const Paragraph = z.object({
  type: z.literal("paragraph"),
  text: z.string().min(1),
});

const List = z.object({
  type: z.literal("list"),
  items: z.array(z.string().min(1)).min(1),
});

const Code = z.object({
  type: z.literal("code"),
  lang: z.string().min(1),
  content: z.string().min(1),
});

const Pagebreak = z.object({
  type: z.literal("pagebreak"),
});

export const Block = z.union([Heading, Paragraph, List, Code, Pagebreak]);
